parameters.jsCode:
const memoryData = $input.first().json;
const episodicMemory = memoryData.content?.episodic_memory || {};
const longTermEpisodes = episodicMemory.long_term_memory?.episodes || [];
const shortTermEpisodes = episodicMemory.short_term_memory?.episodes || [];
const allMemories = [...longTermEpisodes, ...shortTermEpisodes];

const sortedMemories = allMemories.sort((a, b) => {
  const timeA = a.created_at || a.metadata?.timestamp || '';
  const timeB = b.created_at || b.metadata?.timestamp || '';
  return new Date(timeA).getTime() - new Date(timeB).getTime();
});

const conversationHistory = sortedMemories
  .filter(m => m.content && m.content.trim() !== '')
  .slice(-15)
  .map(memory => {
    const role = memory.producer_role || 'unknown';
    const channel = memory.metadata?.channel || 'telegram';
    return `[${role} via ${channel}]: ${memory.content}`;
  }).join('\n');

const userData = $('Unifier').first().json;

return [{ json: { ...userData, conversation_history: conversationHistory || 'No history.', total_memories: allMemories.length } }];

